public class TitleCaseConverter {
    // List of exception words that should not be capitalized unless they are the first word
    private static final List<String> EXCEPTION_WORDS = List.of("of", "the", "is", "and");

    /**
     * Converts a string to title case, with exception handling for certain words.
     * @param input The input string to be converted.
     * @return The converted string in title case.
     * @throws IllegalArgumentException if the input is null or empty.
     */
    public static String toTitleCase(String input) {
        if (input == null || input.isEmpty()) {
            throw new IllegalArgumentException("Input cannot be null or empty.");
        }

        StringBuilder result = new StringBuilder();
        boolean isFirstWord = true;

        for (int i = 0; i < input.length(); i++) {
            char currentChar = input.charAt(i);

            // Check if we are at the start of the string
            if (i == 0) {
                result.append(Character.toUpperCase(currentChar));
                continue;
            }

            // Check if the current character is a letter
            if (Character.isLetter(currentChar)) {
                // Check if the current character is a letter and not part of an exception word
                if (!EXCEPTION_WORDS.contains(String.valueOf(currentChar)) && !isFirstWord) {
                    result.append(Character.toUpperCase(currentChar));
                } else {
                    result.append(currentChar);
                }
            } else {
                result.append(currentChar);
            }

            // Check if we've reached the end of the string
            if (i == input.length() - 1) {
                // Ensure the last character is lowercase if it's not a letter
                if (!Character.isLetter(currentChar)) {
                    result.append(Character.toLowerCase(currentChar));
                }
            }

            // Check if we are at the end of the word
            if (i == input.length() - 1) {
                isFirstWord = false;
            }
        }

        return result.toString();
    }
}
